INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('72aaa251-6e5d-424e-bef6-9414cddf9dd7', 'a05f3c4f-9811-4680-97a8-1c660867afea', 'A component wrapped in `React.memo()` to prevent unnecessary re-renders.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('62c61d77-70a1-45c0-9efb-765d8f679dd5', 'a05f3c4f-9811-4680-97a8-1c660867afea', 'A component that uses `useRef` instead of `useState` to track values without re-rendering.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6866eb57-2715-4652-bd23-8425f91f10fe', 'eaeeac21-c8dd-4cff-ae47-185f356400d3', 'A component that manages its important information through its own local state, so its parent cannot influence that behaviour.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c6d2d9c5-ce9e-412e-b804-6643e0820bf2', 'eaeeac21-c8dd-4cff-ae47-185f356400d3', 'A component that throws an error if it receives any props from its parent.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8b0d9153-0cca-40b0-b327-1efcdcb30006', 'eaeeac21-c8dd-4cff-ae47-185f356400d3', 'A component that only renders static content and never reads from state or props.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a0b1e50c-7b46-482a-b687-b77c7655161a', 'eaeeac21-c8dd-4cff-ae47-185f356400d3', 'A component defined outside of the React tree using plain DOM APIs.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('75553235-a639-46b2-928b-8087800bc7a1', '7365b2dd-426d-4c45-93bf-43510645a83a', 'Remove state from the child components; pass hardcoded data from the common parent; add state to the common parent and pass it down together with event handlers.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3ec79d6a-b09f-4a67-9005-e6555175892a', '7365b2dd-426d-4c45-93bf-43510645a83a', 'Add a context provider at the root; consume the context in both siblings; dispatch actions to update the shared state.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d414f3e0-5c52-41ee-b853-5939661450ff', '7365b2dd-426d-4c45-93bf-43510645a83a', 'Extract shared logic into a custom hook; call the hook in both siblings; export the state from the module.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5554ef45-d898-43bd-82af-44a55733dfd4', '7365b2dd-426d-4c45-93bf-43510645a83a', 'Pass a ref from parent to child; attach the ref to the DOM element; read the ref value in the sibling.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('08a2e922-2379-4725-ba6f-62cf3ba6c1af', '4fbde162-5706-4341-8bfc-a6473cd1236a', 'For each unique piece of state, one specific component owns it; rather than duplicating state, lift it to the common parent and pass it down.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('390a592e-3e9e-49b7-9a4a-2366c6f1807f', '4fbde162-5706-4341-8bfc-a6473cd1236a', 'All application state must be stored in a single top-level component such as `App` and passed to every other component.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7418db7f-7f70-430d-af07-b6dc89b8e5bf', '4fbde162-5706-4341-8bfc-a6473cd1236a', 'State should never be split across multiple `useState` calls — every component may only have one state variable.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7fff9e36-a8da-4970-9da2-0dd0e6ab8324', '4fbde162-5706-4341-8bfc-a6473cd1236a', 'State must always be stored in a database and fetched on every render to ensure freshness.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('45126adb-ceb7-457a-845e-e34e10e48b86', 'b26e51f9-42c3-47c3-969d-19d4725fff66', 'Local variables don''t persist between renders and changes to them don''t trigger re-renders.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f15f96a5-78e8-47ff-aff8-07858f734f0c', 'b26e51f9-42c3-47c3-969d-19d4725fff66', 'Local variables are always undefined inside React components.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7d2fee60-7a03-4d50-859c-789a293f6deb', 'b26e51f9-42c3-47c3-969d-19d4725fff66', 'Local variables can only store primitive values, not objects.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f4eafc89-8fc8-454a-b30b-f8b2f3c189a0', 'b26e51f9-42c3-47c3-969d-19d4725fff66', 'Local variables are shared between all component instances on the page.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('94ff0ee6-cb03-46df-bada-824c576d2c49', 'e8025b50-a8ee-4817-b32c-ee7d2cd559cb', 'An array containing the current state value and a setter function.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ba7d502c-afb0-4c29-bb30-4b9cbacfbbb7', 'e8025b50-a8ee-4817-b32c-ee7d2cd559cb', 'An object with `state` and `setState` properties.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('17ea8e35-c9f1-4c8f-9475-5ec4fbcd5068', 'e8025b50-a8ee-4817-b32c-ee7d2cd559cb', 'The initial state value only.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e5ab3ad3-1f6b-4e60-96e1-d80b50715c18', 'e8025b50-a8ee-4817-b32c-ee7d2cd559cb', 'A tuple containing the previous state and the current state.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4746eecc-9d5f-4867-8eb9-7f7f3e3cc6a6', '9fa0e40b-d7ac-411d-9cde-f0f98f0a1c0b', 'Outside the component function, in React''s own memory keyed to the component''s position in the tree.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('08fdac23-be76-46cd-87cd-9204c7ecb6fd', '9fa0e40b-d7ac-411d-9cde-f0f98f0a1c0b', 'Inside the component function''s local scope as a closure variable.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ba03343c-a84e-46a2-9d1e-7daffa1f106e', '9fa0e40b-d7ac-411d-9cde-f0f98f0a1c0b', 'In the browser''s localStorage.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('88aefee3-18f1-4656-aeb9-9bdf73eece8f', '9fa0e40b-d7ac-411d-9cde-f0f98f0a1c0b', 'In a global JavaScript variable at the module level.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ceabd391-592f-472b-84bc-ff49e6d760e7', '8dfacc50-bbf8-4713-8d62-ca70755190a6', 'Only at the top level of a component or a custom Hook, never inside conditions or loops.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2cfebb89-bf5e-407e-9c60-143e0306493c', '8dfacc50-bbf8-4713-8d62-ca70755190a6', 'Anywhere inside the component, including inside event handlers and loops.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7ab3565d-4469-4d51-b3aa-170da90f878c', '8dfacc50-bbf8-4713-8d62-ca70755190a6', 'Only inside class components.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9914d277-52c1-43fb-b371-5edc474eca4b', '8dfacc50-bbf8-4713-8d62-ca70755190a6', 'Only inside `useEffect` callbacks.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5a14e86d-6581-4066-8005-75c35ccb5439', '27950c77-ce5b-4134-8d6b-84dad6a678ec', 'Each instance has its own isolated state; changing one does not affect the other.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f56d7c85-39ae-46c3-9b63-e72ce86cf4be', '27950c77-ce5b-4134-8d6b-84dad6a678ec', 'They share the same state because they are the same component.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('64a43ccd-aba7-4e01-b3d9-50e934a245e6', '27950c77-ce5b-4134-8d6b-84dad6a678ec', 'One instance is the "primary" and the other mirrors its state.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('419e76e4-21ac-42b7-aa34-642d997c7f53', '27950c77-ce5b-4134-8d6b-84dad6a678ec', 'The parent component automatically keeps their states in sync.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d5af9b39-e3f7-47e2-ada6-4c652d984652', '773cad26-777b-4b8a-aeb3-c7388e4e0a6b', 'Trigger, Render, Commit.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c87cfdb6-66c0-42f3-a6d9-5fc10072e093', '773cad26-777b-4b8a-aeb3-c7388e4e0a6b', 'Mount, Update, Unmount.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1b7deb8b-0f6f-4b40-93f2-4d79dfdd02ab', '773cad26-777b-4b8a-aeb3-c7388e4e0a6b', 'Parse, Execute, Paint.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('22b5fd09-ea36-41af-ae16-1607e7a9b18a', '773cad26-777b-4b8a-aeb3-c7388e4e0a6b', 'Diff, Patch, Flush.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('29f54698-3e99-434d-8c62-c0524e4b4dd8', '94a5a0a3-dd51-416e-b140-00db60f14605', 'The component''s initial render, or a state update in the component or one of its ancestors.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4309893a-fea0-4a15-91fb-fb58b9120366', '94a5a0a3-dd51-416e-b140-00db60f14605', 'A prop change or a context change only.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('821d39e6-2003-452f-8557-fa6c1e1b043b', '94a5a0a3-dd51-416e-b140-00db60f14605', 'A DOM event listener firing or a timer expiring.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('dc55a831-76e4-48d4-ba47-80f8176cbf85', '94a5a0a3-dd51-416e-b140-00db60f14605', 'The user navigating to a new route or the page being refreshed.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('153a735c-4f9a-42d0-a28a-cd3ea84057d2', '7b18b8d1-f2b4-4d26-a0d1-f38faab20ddc', 'The function component whose state update triggered the render, and recursively any components it returns.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7b70344f-fd79-45b2-a878-69e010fe2c62', '7b18b8d1-f2b4-4d26-a0d1-f38faab20ddc', 'Only the root component, regardless of which component''s state changed.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d6a5adc1-dbc4-4aa0-b21c-75db2cc83dcb', '7b18b8d1-f2b4-4d26-a0d1-f38faab20ddc', 'Only the component whose state changed, never its children.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('dab97554-af65-41fa-bda6-3fe91ecdbfa9', '7b18b8d1-f2b4-4d26-a0d1-f38faab20ddc', 'All components in the application simultaneously.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4af463e9-cf24-4c75-aa26-20e5da14db3a', 'a41cf57a-2ed2-4fec-acce-d0fa510783be', 'React only changes the DOM nodes where there is a difference between the previous and the new render output.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d34f04c7-7dee-4096-8674-951411afaa1f', 'a41cf57a-2ed2-4fec-acce-d0fa510783be', 'React removes the entire DOM and recreates it from scratch on every render.', FALSE, 1);
