INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('04fbc2f5-41f9-41bc-bce8-182145361b9c', '96e227ae-c466-479c-bc31-9adecfdc25a0', 'The behavior is undefined when mixing direct values and updater functions.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('eb2de2d5-bda2-4dd0-a0b5-41b2ff4c735d', '2676cd16-b2bc-436b-9912-d2a22bed0199', 'During the next render, when React processes the state update queue.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8b321440-88e9-4eae-83e1-4810862ce128', '2676cd16-b2bc-436b-9912-d2a22bed0199', 'Immediately and synchronously within the current event handler.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1ac70c56-bfbb-4b50-b969-d5815bf23f15', '2676cd16-b2bc-436b-9912-d2a22bed0199', 'In a microtask after the current event handler completes but before re-render.', FALSE, 2);
