INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b6c85f4a-d570-4ec8-bb82-b264ba874703', '58ae664f-fa57-4b37-86fe-f7caf9e2b586', 'Use `splice()` to remove the item in place, then call `setArtists(artists)`.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2272f642-3a49-4186-a03d-3f595b5f32ea', '58ae664f-fa57-4b37-86fe-f7caf9e2b586', 'Set the unwanted item''s value to `null` and call `setArtists(artists)`.', FALSE, 2);
