INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d5e87dee-cbaf-4a7a-bbc9-fa6cbfe318d1', '6eb5446f-8acd-4188-a03f-bf63cd7a9865', '`slice` copies an array or part of it without mutation; `splice` mutates the original array (insert/delete).', TRUE, 0);
