INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9a73d98f-1e6f-4aca-bd2d-c79fddf1a6ac', '51efcfe7-ece3-45a0-b20a-d26e075239c1', 'Passing the function reference (B) is the lazy initializer pattern — React calls it only once during initialization, not on every render.', TRUE, 0);
