INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('63c25b1c-e3bc-4ced-8e9f-9951e1c4d754', '6c5c0dff-527c-44c7-b1fa-e691d9a616be', 'Reserve stack memory, move values to the heap, compact the heap manually.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5d6ee31f-122e-41d2-8868-1cd6164bc9fb', '3391b21d-e05c-4915-9f83-e456f8f444e8', 'It can reclaim unreachable cycles, even when objects still reference each other.', TRUE, 0);
