INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('31d9d01e-f301-46a1-8df4-ff52a8eb199e', '3391b21d-e05c-4915-9f83-e456f8f444e8', 'It works only for primitive values and delegates objects to another collector.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('837ac1f7-7f82-4393-86ad-5fb5a254c5c0', '3391b21d-e05c-4915-9f83-e456f8f444e8', 'It guarantees that every unreachable object is freed immediately after reassignment.', FALSE, 3);
