INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('91271a24-ed8a-4c58-820c-9f7a14e16fc0', '019faeda-7546-488d-a5ec-3a6485a27fe8', 'The key becomes permanently non-collectable because the value points back to it.', FALSE, 2);
