INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1f6b19b9-baf2-4cfa-a950-501427757271', 'ba347b20-5e95-4fcc-b6dd-54d5bc9636a6', 'Because iteration would expose object liveness and make garbage-collection behavior observable.', TRUE, 0);
