INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('171f56dd-fb7a-43b5-b7c1-94ab19082a85', 'ba347b20-5e95-4fcc-b6dd-54d5bc9636a6', 'Because only symbols can be enumerated, while weak collections require object keys.', FALSE, 2);
