INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3d234d55-f008-4fce-be30-0afefba3baaf', 'ea859873-472d-4e8f-a6f5-1ad28d00ed32', 'Use them only for non-critical memory optimizations, because collection timing and finalizer callbacks are not guaranteed.', TRUE, 0);
