INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e297b104-4e89-4ed4-985c-6d262db01d08', 'ea859873-472d-4e8f-a6f5-1ad28d00ed32', 'Treat `FinalizationRegistry` callbacks as the canonical place for network or file cleanup logic.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('71425a70-7af3-4959-9d45-0bef69b81f21', 'ea859873-472d-4e8f-a6f5-1ad28d00ed32', 'Assume `WeakRef#deref()` returns `undefined` immediately after the last strong reference disappears.', FALSE, 3);
