INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('cc31841b-0c92-4fff-930f-ba4a591a0dc1', 'd44d0a6a-f67b-48e3-9755-51ca9f66d1c6', 'Any object with at least one property, because properties count as roots.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6b3cacd8-048e-4759-a89c-e4d21f39c29f', 'd44d0a6a-f67b-48e3-9755-51ca9f66d1c6', 'Only values allocated on the stack, because heap objects must be discovered from stack frames later.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b0910be7-4f7b-4878-bb28-52dfbd9f8bd9', '69a4dd8c-ceac-493f-bd7b-220fa718dccd', 'Because `admin` still references the object, so it remains reachable from a root.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('49c9e4c5-08e9-460a-8131-bfb58e680d86', '69a4dd8c-ceac-493f-bd7b-220fa718dccd', 'Because JavaScript delays collecting every object until the next page reload.', FALSE, 1);
