INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('842c9e22-1447-426d-8d4d-38cdac401c9c', '69a4dd8c-ceac-493f-bd7b-220fa718dccd', 'Because objects with string properties are pinned until all properties are deleted.', FALSE, 3);
