INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('66cbc594-586f-4b76-ac21-7ad69e69bb7d', '34fd2b5a-4902-4622-ac85-a1b4652cda5b', 'Because the engine converts cyclic objects into weak references when their owner is reassigned.', FALSE, 3);
