INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('be5d4cd3-a2f2-4b88-b9ee-d2541dbe35cd', '9738bfdb-9445-42a8-b7e3-4fced97bce7f', 'Reachability ignores object properties entirely and looks only at variable declarations.', FALSE, 2);
