INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('75793df5-3c56-4ad0-b13e-edfb4465537e', '858aee8a-44f1-46bf-b6bd-ae9d98dc469f', 'Incremental collection.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5b88620f-71b5-4b56-8fd6-69fdb3e2bb94', '858aee8a-44f1-46bf-b6bd-ae9d98dc469f', 'Reference counting.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4441e60b-a33f-4a23-a76d-ec2719d70725', '858aee8a-44f1-46bf-b6bd-ae9d98dc469f', 'Tail-call elimination.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8bf7c05e-c1af-401c-b7dd-cf0dd1492799', '858aee8a-44f1-46bf-b6bd-ae9d98dc469f', 'Lazy parsing.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8bb04c51-4500-4b4c-98df-52672bc55e00', 'f65ecddf-0d0b-47de-bb71-80fe79fa5718', 'It creates an accidental global, which can keep data reachable from the global object longer than intended.', TRUE, 0);
