INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b8216da5-a207-4dcd-9624-a986005cf795', 'f65ecddf-0d0b-47de-bb71-80fe79fa5718', 'It throws immediately in every browser mode because undeclared assignments are always syntax errors.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('07c9ab81-ab99-4ffa-a8d5-adae68533345', '91264262-2824-4904-8b0a-e5915ce35672', 'Because the active interval keeps the callback reachable, and that callback keeps `someResource` reachable too.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0ead27fd-7caa-4619-b5ff-b799bfe3a6ad', '91264262-2824-4904-8b0a-e5915ce35672', 'Because `JSON.stringify` duplicates the resource into immortal engine memory each second.', FALSE, 1);
