INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e8835c29-7c93-454d-b873-9933f7d0c285', '31bbe9cc-171e-4b04-8ae8-505cf3e8228e', 'The retained `<td>` can keep the entire table subtree in memory because child and parent nodes still reference one another.', TRUE, 0);
