INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2bc5bffe-cdd3-4b08-aa77-26e2c75abf70', '2597d2ae-5023-4d37-8e52-f51718bdfafb', 'The first heap snapshot shows many strings even before any interaction occurs.', FALSE, 2);
