INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ffb26c36-2c98-4bff-aaa0-5123a5ed9478', '94bd134f-68bb-436f-a4c2-adf6b0e42fdf', 'Primitive values are typically stored on the stack, while objects, arrays, and functions are stored on the heap.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('88afe1ca-8bc1-4b7f-8719-ee20343b0d70', '94bd134f-68bb-436f-a4c2-adf6b0e42fdf', 'Everything in JavaScript is stored only on the stack because memory is managed automatically.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3f42cd53-0fe1-4f95-964a-438b4725fd70', '94bd134f-68bb-436f-a4c2-adf6b0e42fdf', 'Primitive values live on the heap, and only DOM nodes are allowed on the stack.', FALSE, 2);
