INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('78752217-aff4-4cc3-b234-f22797961d85', '564bbb73-572f-4cc4-ad0f-44ce42935993', 'Because mark-and-sweep checks whether an object is still connected to a root, not merely whether it is referenced by another non-root object.', TRUE, 0);
