INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2abf65d9-7710-45d0-b9e5-aad446a4a2c4', 'cbcef1a6-2dd9-488e-aed7-d1e816c0a8eb', 'It reduces the retained memory by breaking the reference to the older large object, even though the closure shape still exists.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('052bd20d-fc64-42e1-86e8-e81eeed12350', 'cbcef1a6-2dd9-488e-aed7-d1e816c0a8eb', 'It forces the engine to collect the closure synchronously before the next statement runs.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6d175560-a0c6-42c6-b56f-fdc730e77899', 'cbcef1a6-2dd9-488e-aed7-d1e816c0a8eb', 'It converts the closure into a weak reference that no longer retains any lexical scope.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ac6d67be-204b-480e-b9eb-cdb2e69e8ab2', 'cbcef1a6-2dd9-488e-aed7-d1e816c0a8eb', 'It has no effect because closures in JavaScript can never be influenced by reassigning captured values.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c67ed4b9-c730-40f3-bea5-0dbc95f57e88', 'e6631f0a-eb0f-4568-b13c-b8dcb2b8ecdb', 'The active interval keeps the callback reachable, and the callback keeps `cache` reachable through its closure.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('127e47ef-8a1c-4248-83ac-96647fb28aab', 'e6631f0a-eb0f-4568-b13c-b8dcb2b8ecdb', '`cache` becomes weakly referenced as soon as `start` returns, so the array is collectable between interval ticks.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b9b32b4c-66d4-412a-953e-74625cc593aa', 'e6631f0a-eb0f-4568-b13c-b8dcb2b8ecdb', 'The array leaks only because it contains strings; an array of numbers would be collected normally.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('da98037a-8674-437b-b028-94b5029d4558', 'e6631f0a-eb0f-4568-b13c-b8dcb2b8ecdb', '`console.log` pins every value it prints in developer tools memory until the page is refreshed.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2f3af14b-9c46-4daf-b3aa-4e32bd347157', '6bdea6f9-38f9-4028-9e54-849275bc90c0', 'Use `Map<string, WeakRef<Value>>`, and pair it with cleanup logic such as `FinalizationRegistry` or explicit eviction if dead entries can accumulate.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('333a3826-3570-497d-96e1-a290ebb3b983', '6bdea6f9-38f9-4028-9e54-849275bc90c0', 'Use `WeakMap<string, Value>` because weak collections are designed specifically for string-keyed caches.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0b653dc3-6f9d-4eaa-ba1b-0f237ed5052a', '6bdea6f9-38f9-4028-9e54-849275bc90c0', 'Use a plain global object as the cache because properties on the global object are easy for the collector to reclaim lazily.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7d702e05-90d1-470c-92d6-004cf8409682', '6bdea6f9-38f9-4028-9e54-849275bc90c0', 'Use `Set<Value>` and rely on object equality to recover the value from the URL later.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9683add6-7cf8-4709-bb59-86a031780fba', 'f169c153-f4e4-42a8-9db8-b5ccdb998e62', 'Because a reachable child node can keep the broader DOM subtree alive through parent-child references, even after the subtree is removed from the document.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6fb7652a-e157-456a-acc9-284a1cbfad48', 'f169c153-f4e4-42a8-9db8-b5ccdb998e62', 'Because removed DOM nodes are frozen until the next full page navigation.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c44afe0c-c639-4e92-aa0d-b992529129e8', 'f169c153-f4e4-42a8-9db8-b5ccdb998e62', 'Because only root DOM nodes can be garbage-collected; descendant nodes are never collected independently.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('beafa5d3-233c-48f7-90ea-3f44b132fd1b', 'f169c153-f4e4-42a8-9db8-b5ccdb998e62', 'Because DevTools itself automatically preserves any node that was queried with `querySelector`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d2821e28-1086-4411-8b6a-3bb4ffc4ca41', '9a42707d-2aa8-46f1-8f79-a1911cd9d0f8', 'Remove the unused closure that captures the previous object, or set the previously captured object to `null` before storing the replacement.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e9c54d28-f4fc-42bc-831b-5d1e71c4cf2a', '9a42707d-2aa8-46f1-8f79-a1911cd9d0f8', 'Wrap the replacing logic in `Promise.resolve().then(...)` so the engine can collect old closures after each microtask.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('72db5eb5-2b7c-47e7-a7a7-ee15c0370676', '9a42707d-2aa8-46f1-8f79-a1911cd9d0f8', 'Convert the large string into a template literal so V8 interns it automatically.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a6ac4496-c0a4-44b2-a44a-de6ea415804b', '9a42707d-2aa8-46f1-8f79-a1911cd9d0f8', 'Call `delete` on the function name after each replacement so the lexical environment can be compacted.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('871088b8-4f8e-461f-ad06-2b1ce1bf59e2', 'e4c13b1f-e215-41e7-96ce-689ee22ed19a', 'The post-GC baseline keeps climbing over time, often together with a steadily increasing node count.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('bba8fcbf-d1c5-48ef-9cce-99b4f71fe275', 'e4c13b1f-e215-41e7-96ce-689ee22ed19a', 'The heap grows while a user action is running and then drops close to its prior baseline after collection.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a6eddcd8-29b0-4d9f-bd28-4fce084a2946', 'e4c13b1f-e215-41e7-96ce-689ee22ed19a', 'The first recorded GC event causes a large downward spike in heap usage.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5c29886e-9fa1-49bd-9353-cfdf314d3fa4', 'e4c13b1f-e215-41e7-96ce-689ee22ed19a', 'A single heap snapshot contains many strings and arrays, but there is no time-based comparison.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b87bffa4-a7d5-4c40-a065-2be129382322', '95e2efe5-ac1d-4adc-b789-f3a4b98505db', 'The flags can help inspect or force collections during debugging, but they do not fix leaks unless the code stops keeping unwanted references alive.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('846dace0-89de-4e7a-bbe7-12a486ce2ed5', '95e2efe5-ac1d-4adc-b789-f3a4b98505db', 'The flags guarantee that all unreachable memory is reclaimed immediately after every event loop turn in production.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7e9f6e58-b0fc-4101-a3b2-6efffaa7f973', '95e2efe5-ac1d-4adc-b789-f3a4b98505db', 'The flags convert all weak references into strong ones so retention paths are easier to inspect.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f1557489-ecf8-4b83-9080-94653109431f', '95e2efe5-ac1d-4adc-b789-f3a4b98505db', 'The flags disable mark-and-sweep and replace it with deterministic reference counting for repeatable tests.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('30e72686-0feb-4166-90a0-f72d50851839', '672bda85-d046-4c5f-bc84-c20168085d42', 'A pure reference-counting collector could leak the cycle, while a modern mark-and-sweep collector can reclaim it because the cycle is unreachable from roots.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8e7e6e6e-343b-4f27-9d86-f365a4e708fd', '672bda85-d046-4c5f-bc84-c20168085d42', 'Both collectors must retain the cycle forever because mutual references are stronger than root reachability.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('01966274-c249-4dc1-b052-0a5c6271943a', '672bda85-d046-4c5f-bc84-c20168085d42', 'Only mark-and-sweep leaks the cycle, because it cannot follow internal references after a root is removed.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9e15ee8e-6fc8-4f2c-a150-a14ded903064', '672bda85-d046-4c5f-bc84-c20168085d42', 'Neither collector can ever reclaim cyclic data structures in JavaScript.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2eb1ba59-61bb-4063-a8d9-8f08a05eebc4', 'c9a4c652-60ac-4b93-8ed1-423716e43c50', 'You need to iterate entries or report a deterministic cache size as part of the program''s behavior.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7a241d61-0049-4678-9f15-03af904bd360', 'c9a4c652-60ac-4b93-8ed1-423716e43c50', 'Your keys are objects that should not keep values alive forever.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('61f7cd8c-1dd8-4ec6-9eaa-e8f76d7e7262', 'c9a4c652-60ac-4b93-8ed1-423716e43c50', 'You want the collector to treat the keys as weakly reachable where possible.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('cb02cb4c-3180-4fb2-ad0c-4124331daf24', 'c9a4c652-60ac-4b93-8ed1-423716e43c50', 'You do not want to accidentally expose object liveness through the API.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8e1d2163-0085-49af-8fce-4e3b716c8015', '037baf86-506f-418a-8fa8-a1ef8c814c7b', 'Declare `buffer` with `let` or `const` in the intended scope, and run in strict mode or ES modules so undeclared assignments fail instead of creating globals.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d17d5012-a95e-410c-bc6a-7b226d29afb4', '037baf86-506f-418a-8fa8-a1ef8c814c7b', 'Leave `buffer` undeclared, but assign `null` to it at the end of every function call so the global object stays synchronized.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8d57b477-dff0-4235-ab1e-342183e4c3bb', '037baf86-506f-418a-8fa8-a1ef8c814c7b', 'Wrap the function body in `setTimeout(..., 0)` so the assignment happens outside the current lexical environment.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('828c0482-056b-4d76-844f-96348ae9a437', '037baf86-506f-418a-8fa8-a1ef8c814c7b', 'Convert `data` to JSON before assignment so the engine stores it outside the root set.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ac14f574-fe9b-4a74-b1ec-c08155126187', '96fed79b-331a-4ba8-87b4-3ffd60ff42ad', 'Because the `Map` still strongly holds the URL keys and `WeakRef` wrapper entries, so dead cache slots accumulate unless you evict or clean them up.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d95e29c6-a963-4e90-b9af-66d6ad0269be', '96fed79b-331a-4ba8-87b4-3ffd60ff42ad', 'Because `WeakRef` values are promoted to strong references whenever they are stored inside a `Map`.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7083a5e3-ae30-4692-b485-a354e3330dda', '96fed79b-331a-4ba8-87b4-3ffd60ff42ad', 'Because blobs fetched over HTTP can never be garbage-collected in JavaScript runtimes.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2ff1d544-e0d5-4d5e-831a-2a4737fbf1d3', '96fed79b-331a-4ba8-87b4-3ffd60ff42ad', 'Because `fetch` returns immortal internal objects that survive until browser shutdown.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ec868e41-628e-4db3-adc3-226634d5af1d', 'b1a95578-8910-4b0a-911d-14525aaecdd3', '`Date instance -> Date.prototype -> Object.prototype -> null`', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2fa2869c-74e6-4020-8787-2b344a498396', 'b1a95578-8910-4b0a-911d-14525aaecdd3', '`Date instance -> Object.prototype -> Date.prototype -> null`', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('bb8d157c-7121-467f-b36b-5f46ca5a51c5', 'b1a95578-8910-4b0a-911d-14525aaecdd3', '`Date instance -> Date -> Function.prototype -> null`', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8ee81fab-fa47-45b7-8fc1-a8d68c435ad7', 'b1a95578-8910-4b0a-911d-14525aaecdd3', '`Date instance -> Object.prototype -> null`', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9f459da9-7e76-4334-9fc9-0036d8c044be', 'a3c0259e-8196-44e8-a54d-4a6de388c2cc', 'It still uses `Date.prototype.getTime()` because built-in methods always win.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3585619f-c3a1-48b7-968b-e06770fb2ff3', 'a3c0259e-8196-44e8-a54d-4a6de388c2cc', 'It uses the new function on `myDate`, because the own property shadows the prototype method.', TRUE, 1);
