INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('95707164-095e-4933-a055-348a14d82345', 'a3c0259e-8196-44e8-a54d-4a6de388c2cc', 'It becomes ambiguous, so JavaScript alternates between both methods.', FALSE, 3);
