INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('64daf6e4-2039-43e4-a3df-4a8d592bba69', 'f8ee417d-f435-4a48-8486-b9b7af05ef33', 'It throws automatically because `localStorage` cannot be used on HTTPS pages.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a32f00b7-3703-4390-827c-009bfee44566', 'd3a5f1de-cd6e-4a20-94bd-30caa83d18ba', 'It is slower than `setItem`, but otherwise safe because `length` is treated like any other key.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7ce94b46-c53f-4d73-be0d-45514243c2c9', 'd3a5f1de-cd6e-4a20-94bd-30caa83d18ba', 'It risks colliding with built-in storage members, and object-like access skips the `storage` event behavior described by the source.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ecfa62af-0a22-4e1c-bbf3-3e418795f080', 'd3a5f1de-cd6e-4a20-94bd-30caa83d18ba', 'It stores numeric values as numbers, which breaks UTF-16 encoding.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5a4f770c-5391-4adc-a630-df823e41b038', 'd3a5f1de-cd6e-4a20-94bd-30caa83d18ba', 'It works only in Firefox because Chromium blocks bracket notation on storage objects.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4df8e3a4-661c-4173-8675-9923de29bdbf', 'ac811e1e-07b6-4043-8094-89160656d318', 'Append each row directly, set `innerText` on every iteration, and assign inline styles for all visual changes.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('925cdd30-ac85-45d8-af69-6fdf2d387119', 'ac811e1e-07b6-4043-8094-89160656d318', 'Build rows in a `DocumentFragment`, set plain text with `textContent`, and use classes for styling before appending once.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('97d88294-7060-450b-a331-f941d0b2c0c9', 'ac811e1e-07b6-4043-8094-89160656d318', 'Use `innerHTML += ...` inside the loop because string concatenation eliminates DOM work entirely.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('83821cd3-1bc0-4da7-8e88-f78d1b94b1fb', 'ac811e1e-07b6-4043-8094-89160656d318', 'Query the whole document after each append so layout can stabilize incrementally.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('55a2c001-3379-45a6-9aed-db6fc6c38322', '516f6837-ceb4-4994-a59f-dab753f70ec8', 'Correct. A fragment always guarantees lower layout cost than any direct append strategy.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('16cc79b3-697b-4eac-b088-325c884ca4d1', '516f6837-ceb4-4994-a59f-dab753f70ec8', 'Mostly correct, but only if the page also switches all events to capture mode.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('95e02934-1fda-4276-bd75-80cf4ba39ff1', '516f6837-ceb4-4994-a59f-dab753f70ec8', 'Too absolute. Fragments are useful for batching and readability, but the performance win is not guaranteed to be large or universal.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0bd13c34-8809-423e-a1c8-aa63550cc518', '516f6837-ceb4-4994-a59f-dab753f70ec8', 'Incorrect because fragments are only for `<template>` elements and cannot be appended manually.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3d4d8cd1-b8b9-44a3-8248-36ce5b174587', '2c6a04a8-89af-4b92-b3aa-9b79cfecf844', '`<body>` is the sibling of `<h1>`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('95364ba3-bcca-4f8b-a3e0-5c8273f3cf62', '2c6a04a8-89af-4b92-b3aa-9b79cfecf844', '`<body>` is the child of `<h1>`.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('cfa0c272-3633-415d-860f-d9f4cfca0248', '2c6a04a8-89af-4b92-b3aa-9b79cfecf844', '`<body>` is the parent of `<h1>`.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('18a77772-dc4d-4eca-b311-0f7adf492434', '2c6a04a8-89af-4b92-b3aa-9b79cfecf844', '`<h1>` is the parent of `<body>` because it appears first.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('642e7801-7dd8-4dc5-a96f-0ac3bbfa9940', 'de1be6aa-4427-4882-80ff-39cd5b997dac', 'The `<title>` element node directly stores the string `DOM Tutorial` as its own `nodeValue`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e66d15cb-ddac-4125-8579-d579eefb1a28', 'de1be6aa-4427-4882-80ff-39cd5b997dac', 'The `<title>` element contains a text node child whose value is `DOM Tutorial`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6298e62b-2810-48e5-a9bf-8e5477352451', 'de1be6aa-4427-4882-80ff-39cd5b997dac', 'The text is stored only in `document.documentElement`, not under `<title>`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2f2e4807-bab9-4b66-98bb-61972d25591c', 'de1be6aa-4427-4882-80ff-39cd5b997dac', 'The text can be accessed only through `innerText`; child-node navigation cannot reach it.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('efd0cc00-fe9f-420f-a617-b47f4c018e44', '0348dfc1-db9b-4e86-a4e3-2ff99466bc01', '`document.body`, because it includes both `<head>` and `<body>`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f83987b1-6ed5-46bf-a895-b19542dc13da', '0348dfc1-db9b-4e86-a4e3-2ff99466bc01', '`document.firstChild`, because it always resolves to the `<html>` element across browsers.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4f53c45f-155e-4dac-b31b-8607e59194ef', '0348dfc1-db9b-4e86-a4e3-2ff99466bc01', '`document.documentElement`, because it represents the full document root.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b08ba267-7236-4b0e-abab-96c6a875953e', '0348dfc1-db9b-4e86-a4e3-2ff99466bc01', '`document.nodeValue`, because it contains the serialized DOM.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2a772262-f5a7-45a7-a0c6-bbbaa9f31495', 'c8a8f95e-77d5-4e4b-b762-6c4bfedbaf5b', '`#text`, because all visible elements expose the node name of their text child.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('18afdfbb-e5ac-4c2e-854f-afefbe07edd2', 'c8a8f95e-77d5-4e4b-b762-6c4bfedbaf5b', '`h1`, because `nodeName` always preserves the original tag casing.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('36513454-08d6-4056-a2dc-ebc36901636d', 'c8a8f95e-77d5-4e4b-b762-6c4bfedbaf5b', '`H1`, because HTML element `nodeName` is the uppercase tag name.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5ee33d0f-669b-41ed-9379-8880359bfde0', 'c8a8f95e-77d5-4e4b-b762-6c4bfedbaf5b', '`My First Page`, because `nodeName` for elements is their visible text.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a324e467-4fc5-4682-80f0-1ccb092fd1b2', 'bb8d0ec1-14d3-45f0-b1ff-8b7273cd0419', '`1`, because the document is treated as the root element node.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('27f8a331-a0ac-43e0-8e50-55dc5050e53e', 'bb8d0ec1-14d3-45f0-b1ff-8b7273cd0419', '`3`, because the document is the top-level text node.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9474c360-ad14-4978-8f0a-4a8dcf6c21fc', 'bb8d0ec1-14d3-45f0-b1ff-8b7273cd0419', '`8`, because the document is a special comment wrapper.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5910b4e8-22d2-4d37-b389-dc24f15c7eb4', 'bb8d0ec1-14d3-45f0-b1ff-8b7273cd0419', '`9`, because the document itself is a `DOCUMENT_NODE`.', TRUE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b5ae37b8-68b9-441b-9d27-2519cceb20cf', '055ceab2-dcb5-4591-9837-7049a353e04c', '`childNodes`, because it filters out non-element nodes automatically.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('451498e9-b7f2-4e61-bc55-67ba167b04a3', '055ceab2-dcb5-4591-9837-7049a353e04c', '`children`, because it excludes text and comment nodes.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a2961785-1946-4b3a-bcff-02bd8e05ffb3', '055ceab2-dcb5-4591-9837-7049a353e04c', '`firstChild`, because it always resolves to the first element node.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0f0a06c6-541e-47cf-a652-176ebf9cec13', '055ceab2-dcb5-4591-9837-7049a353e04c', '`nodeValue`, because it enumerates element descendants only.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('191f3c7a-0368-4d26-881c-93bdc1b58c12', '2ba01328-f26e-43fd-8661-abd16f1de893', '`firstChild`, because it ignores whitespace nodes in HTML documents.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7f2e17b8-db11-420a-a044-6ab785ce51e8', '2ba01328-f26e-43fd-8661-abd16f1de893', '`firstElementChild`, because it ignores non-element nodes.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('45bd9726-1bf1-4051-9678-c6f85718daf6', '2ba01328-f26e-43fd-8661-abd16f1de893', '`childNodes[0]`, because node lists exclude comments and whitespace.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('28e63003-1e1d-44dc-84e8-a8b224f8d816', '2ba01328-f26e-43fd-8661-abd16f1de893', '`previousElementSibling`, because it normalizes the first child automatically.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('395a4180-5985-4635-a1a8-c55dea18228d', '3c331fb2-4fe8-4b1a-b38f-0667f652adb8', 'They are interchangeable in HTML because browsers strip text nodes between elements.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('97caf50c-01fb-46a8-ab99-7f11a6c7b782', '3c331fb2-4fe8-4b1a-b38f-0667f652adb8', '`nextSibling` may return a text node, while `nextElementSibling` skips non-element nodes.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e7c25d96-178a-46a6-9511-506151c7c5d1', '3c331fb2-4fe8-4b1a-b38f-0667f652adb8', '`nextElementSibling` returns a `NodeList`, while `nextSibling` returns a single node.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0d80a22c-9dca-47cc-ae4f-a8a82e6dba2d', '3c331fb2-4fe8-4b1a-b38f-0667f652adb8', '`nextSibling` works only on text nodes; `nextElementSibling` works only on elements with IDs.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('078ca8d2-0821-429d-8acf-f38708ad6379', 'be4599aa-82b8-4425-8027-1aa76d8f3324', 'Every node is an element, but some elements are not nodes when they have text children.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c000d4a1-ac3a-4404-8dda-0ff39a400ede', 'be4599aa-82b8-4425-8027-1aa76d8f3324', 'Elements are a specific kind of node, but text and comment nodes are not elements.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d42d645c-b0c2-4f6c-9de3-2ac10692acb9', 'be4599aa-82b8-4425-8027-1aa76d8f3324', 'Only comments and attributes are nodes; elements live outside the node tree.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5bc92557-0920-40b8-b77c-4da746172e84', 'be4599aa-82b8-4425-8027-1aa76d8f3324', 'Elements become nodes only after they are selected with `querySelector`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('bfff3ef1-433f-4836-a677-c64546f52caa', '1dadda8f-46e5-48b4-9798-c667b2716ed6', '`parentNode` always returns the document, while `parentElement` returns the actual HTML parent.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b7c4120f-ca77-402a-bda2-f661bae5e88a', '1dadda8f-46e5-48b4-9798-c667b2716ed6', 'For typical element traversal, either one generally gives the expected parent element.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('abff5a8d-23a5-40b1-b779-1aeca22599a6', '1dadda8f-46e5-48b4-9798-c667b2716ed6', '`parentElement` is required for all nested elements because `parentNode` only works on text nodes.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5e224e1b-10bf-4bf2-9bfa-1c3c3a66023f', '1dadda8f-46e5-48b4-9798-c667b2716ed6', 'They return the same value only when the element has no siblings.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5e14d717-68e2-47d8-9db4-01b15358d81c', '21a754f8-160d-4db7-9fc4-39f0b2ed72ea', 'Target, bubbling, capturing.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('490e2c7f-6e28-4797-852d-cb764d0851e8', '21a754f8-160d-4db7-9fc4-39f0b2ed72ea', 'Capturing, target, bubbling.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b7f64cb8-3192-4512-af5f-8f449e2ed9c4', '21a754f8-160d-4db7-9fc4-39f0b2ed72ea', 'Bubbling, target, capturing.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('674db3de-7089-489b-a2f1-8d9cc0f4c065', '21a754f8-160d-4db7-9fc4-39f0b2ed72ea', 'Capturing and bubbling only; there is no target phase.', FALSE, 3);
