INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7a1d1110-237d-4069-b4e6-5119d32ac940', '44f296c2-3558-4c9b-b8a5-e7cf12f2b801', '`event.phase`', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7aa663f6-e34c-45aa-a27c-1a8bddaee45e', '44f296c2-3558-4c9b-b8a5-e7cf12f2b801', '`event.target`', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('26f9183c-75d4-4214-b84c-29b6957bbb4f', '44f296c2-3558-4c9b-b8a5-e7cf12f2b801', '`event.pathName`', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f76aa022-f8c5-4dbe-be77-68344902ea7f', '44f296c2-3558-4c9b-b8a5-e7cf12f2b801', '`event.currentPhase`', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e47296b9-5674-4525-ab95-7017b53a4235', 'cd4a7a3c-0e64-4b9f-babe-ae7ea87c32fc', 'Because delegated listeners automatically clone themselves onto new children.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9894d72d-cf27-4cfe-93c6-e67f9b3e31e3', 'cd4a7a3c-0e64-4b9f-babe-ae7ea87c32fc', 'Because bubbling lets a parent element handle events that started on child elements.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6cd2d880-9606-44ad-8634-77f444776dd5', 'cd4a7a3c-0e64-4b9f-babe-ae7ea87c32fc', 'Because capture mode disables `event.target`, making parents easier to manage.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a4dba2ba-caf4-4ff1-af1d-4bb38b331be6', 'cd4a7a3c-0e64-4b9f-babe-ae7ea87c32fc', 'Because delegated listeners skip the target phase entirely.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6ec23b95-08d6-4100-a398-be61fff6be11', 'f594685f-5c1b-4047-a58f-9c593691c56b', 'It works only for bubbling listeners and has no effect during capturing.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ba1a573c-c3ff-44ad-9180-0cbdfdc816d0', 'f594685f-5c1b-4047-a58f-9c593691c56b', 'It prevents the event from reaching ancestor listeners, and it can also be used in the capturing phase.', TRUE, 1);
