INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('056dea9c-76b9-4629-8bab-f0024d410493', 'f594685f-5c1b-4047-a58f-9c593691c56b', 'It changes `event.target` to the nearest ancestor node.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0507a4ea-dc9a-47c4-b728-4d32c09bc455', '58279704-7ba4-44c6-8e36-647d9e3bae69', 'On the `button`, because only the clicked element can receive the event.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('acaf9011-1077-43ba-8dd3-959d4fcc779e', '58279704-7ba4-44c6-8e36-647d9e3bae69', 'On the `div`, which handles bubbled events from its child button.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0540518b-9db3-48a9-bff9-2d01bda8d394', '58279704-7ba4-44c6-8e36-647d9e3bae69', 'On `document`, because delegation requires the root node.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a833b3ec-7471-4a5a-8a64-c848c72433be', '58279704-7ba4-44c6-8e36-647d9e3bae69', 'On the `span`, because it sits between the button and the div.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('817114a0-c487-4ae9-8130-f35532643c30', '81a741e8-194e-44a1-a239-28e03e151838', 'Because `event.target` always points to the parent listener unless the tag name is checked.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c04bded6-9fc7-470a-b969-830a80f301cc', '81a741e8-194e-44a1-a239-28e03e151838', 'Because the parent may receive clicks from other descendants, and the handler should react only to button targets.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('79aa635f-a2d7-41cb-b1df-db34c8b6649e', '81a741e8-194e-44a1-a239-28e03e151838', 'Because `addEventListener` requires a `tagName` check for bubbling to work.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('069c7452-92a5-4747-893f-119f93798c29', '81a741e8-194e-44a1-a239-28e03e151838', 'Because browsers dispatch click events only to uppercase tag names.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e8b39e87-1484-4205-83e9-3317265538d0', 'ca37e3c1-0e6e-468f-8f49-0c9d4b2a30b5', 'The new button requires one additional listener, but existing listeners can be reused.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e97ed9f1-e27d-42d6-8e5a-14865cf84952', 'ca37e3c1-0e6e-468f-8f49-0c9d4b2a30b5', 'The new button is handled automatically by the existing parent listener.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ad71f235-84b5-4894-bd17-fdacd4f7e9c0', 'ca37e3c1-0e6e-468f-8f49-0c9d4b2a30b5', 'The browser moves the parent listener onto the new button during reflow.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('77ef3630-bcee-4595-98a5-efda3c05fdec', 'ca37e3c1-0e6e-468f-8f49-0c9d4b2a30b5', 'The new button is ignored until `querySelectorAll` is called again.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7fd511a7-7b92-4483-87c2-f935d4b12564', '734353a6-9ccc-4454-b1bd-e9d98f474f40', 'Because `querySelectorAll` returns a `NodeList` that supports `forEach` in the example.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('331d2181-e667-432a-a685-57210ccf7870', '734353a6-9ccc-4454-b1bd-e9d98f474f40', 'Because `getElementsByTagName` cannot select buttons inside a `div`.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('222a5455-2033-4326-b267-78ffb447359e', '734353a6-9ccc-4454-b1bd-e9d98f474f40', 'Because `querySelectorAll` automatically delegates events to matching nodes.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d0ed79ba-a200-4a56-a7f1-e90860195270', '734353a6-9ccc-4454-b1bd-e9d98f474f40', 'Because `HTMLCollection` values cannot contain elements with text.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('56acef60-0d6f-4ee7-a1e3-27296cd1527d', '3882d47d-581d-4b86-97b2-b084510fe18a', '`button was clicked` is logged anyway because all clicks inside the div are treated as button clicks.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('db7144f4-63a4-4623-b4dc-b5751b3d2670', '3882d47d-581d-4b86-97b2-b084510fe18a', 'Nothing is logged by that branch because the target does not satisfy the `BUTTON` check.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e05a4d09-a554-4531-8c2a-5aec25aa2456', '3882d47d-581d-4b86-97b2-b084510fe18a', 'The event stops bubbling automatically at the div because the condition fails.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c3c6d6e7-0d93-4ac2-a86b-b3bf8d278731', '3882d47d-581d-4b86-97b2-b084510fe18a', 'The listener is removed from the div after the first non-button click.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('eae16c3f-b8ab-46f6-a20a-caa217b059ab', '811faf65-c637-460c-aa16-6ff91cacf605', '`#outer`, then `#inner`, then `button`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('077aa4ee-154a-455c-aa09-2506bd9648b6', '811faf65-c637-460c-aa16-6ff91cacf605', '`button`, then `#inner`, then `#outer`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('55621a76-ff11-4058-9880-e9ee208e8da1', '811faf65-c637-460c-aa16-6ff91cacf605', '`#inner`, then `button`, then `#outer`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f14bb329-4e3b-49cb-a102-6d847c9e9bb7', '811faf65-c637-460c-aa16-6ff91cacf605', 'The order is browser-dependent because bubbling has no defined sequence.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('578ed266-d89d-4bfa-8d31-73bfe2523328', 'ec57c28d-d624-41d6-b3ad-9116293f3cf5', 'Call `event.capture()` inside the handler before the click occurs.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f24826a4-b5c8-42d8-ac8b-85c0ee6660e0', 'ec57c28d-d624-41d6-b3ad-9116293f3cf5', 'Pass `true` as the third argument to `addEventListener`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0201889b-fee2-419d-89c5-cac55958fc7c', 'ec57c28d-d624-41d6-b3ad-9116293f3cf5', 'Register the target element last so it runs first.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a0c8c7f5-888d-4345-8cd8-010db8b26e18', 'ec57c28d-d624-41d6-b3ad-9116293f3cf5', 'Use `querySelectorAll` instead of `getElementById` for the listeners.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9d9c717a-f572-4d39-be8c-f77f00e8dc9d', '0899faed-468c-4532-9378-8e64d1498ff7', 'Only the button''s handler runs; ancestor handlers are skipped.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('900d2dba-017a-499b-a3c0-4ac31423903a', '0899faed-468c-4532-9378-8e64d1498ff7', 'The button handler is skipped, but the ancestor handlers still run.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6516423c-c301-448a-a895-d8d706c80e30', '0899faed-468c-4532-9378-8e64d1498ff7', 'The event changes from bubbling to capturing.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9d44cda2-3845-4ba1-aebd-73d238a0815f', '0899faed-468c-4532-9378-8e64d1498ff7', 'The event still reaches ancestors, but only if they were added before the button handler.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6bb57fa0-5702-4f8d-b542-7cab0a39909b', '8b24c1fc-b6f8-4dc4-90d0-c10624b0ae7c', 'Bubbling goes from target to outer ancestors, while capturing goes from outer ancestors down to the target.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('759f5b60-79ef-4e5c-bd17-636300bc1d27', '8b24c1fc-b6f8-4dc4-90d0-c10624b0ae7c', 'Bubbling and capturing have the same direction; only listener timing differs.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('87cf9173-8dfd-4285-a19b-9e8296b8daa1', '8b24c1fc-b6f8-4dc4-90d0-c10624b0ae7c', 'Capturing applies only to keyboard events, while bubbling applies only to mouse events.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b64738ca-bf51-4778-b66a-693fb4b7ef70', '8b24c1fc-b6f8-4dc4-90d0-c10624b0ae7c', 'Capturing starts at the target element and bubbling starts at `document`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('405f4647-59d2-4e80-970e-c4b677e8d9a2', 'ac85523d-c46a-4edd-a09f-a70c90fdcb02', 'Because `event` contains the method needed to stop propagation.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a0ec9503-8c5e-402e-ba0b-0264fc1c3f27', 'ac85523d-c46a-4edd-a09f-a70c90fdcb02', 'Because handlers must always declare exactly one parameter in JavaScript.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('27bf3337-1c9b-4ee5-b69a-7c7f1b95df4a', 'ac85523d-c46a-4edd-a09f-a70c90fdcb02', 'Because bubbling works only when the event object is renamed to `event`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('67a8763b-4620-4e48-9400-fe64ca32042f', 'ac85523d-c46a-4edd-a09f-a70c90fdcb02', 'Because `addEventListener` passes the clicked element itself, not an event object.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ff88c4ba-3a26-4685-9465-917a1367fc98', '4318d1e6-03ff-4f4f-bbec-6fec52e21c4e', 'It is scoped to one tab only and disappears on refresh.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0f56e9c2-d705-41ac-8571-a136ef451335', '4318d1e6-03ff-4f4f-bbec-6fec52e21c4e', 'It is shared across the same origin and persists across browser restarts.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f3c949c2-8131-4495-a992-3781effb4366', '4318d1e6-03ff-4f4f-bbec-6fec52e21c4e', 'It is shared across all subdomains and protocols automatically.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4119dc1d-60d5-4bc6-ae95-a02270c354de', '4318d1e6-03ff-4f4f-bbec-6fec52e21c4e', 'It is sent to the server with every request like cookies.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('eebee5df-feb9-415a-b522-82fee5aa5617', '48d96422-40ca-4d6d-b629-f11a79c0e586', 'Because object-like access stores values as binary blobs, while `setItem` stores strings.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6433e722-43ac-4d7b-a02d-20926c8e176b', '48d96422-40ca-4d6d-b629-f11a79c0e586', 'Because object-like access can conflict with built-in members like `length`, and it does not trigger the `storage` event.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6fd5438c-f2cc-4fa5-8039-4a2b720133d7', '48d96422-40ca-4d6d-b629-f11a79c0e586', 'Because object-like access works only in `sessionStorage`, not in `localStorage`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ed191fae-b6a3-4e21-ab37-b60cf7b28a23', '48d96422-40ca-4d6d-b629-f11a79c0e586', 'Because `setItem` is required only when the value is a number.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5081aabe-5d68-43f6-9f5f-d70a4d58103e', 'd79b6e11-d888-42da-bbfc-a531f7b9feee', 'It is stored as a structured clone and retrieved as the same object automatically.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('fb76c94e-6742-4f38-8970-5dfa960b8a61', 'd79b6e11-d888-42da-bbfc-a531f7b9feee', 'It is stored as `[object Object]` unless you serialize it, for example with `JSON.stringify`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4be887c2-8db8-4882-acd2-81ccf84476f2', 'd79b6e11-d888-42da-bbfc-a531f7b9feee', 'It throws because `localStorage` accepts only arrays and strings.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5300e571-52b7-42ea-9d2d-e2dfd41a1204', 'd79b6e11-d888-42da-bbfc-a531f7b9feee', 'It is stored as UTF-8 bytes and must be decoded with `TextDecoder`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e06c4ab6-bfbe-4789-900b-4b5be2557672', 'ca15dc81-fe48-4217-976c-ef00eba508f1', 'Both tabs receive the event, including the tab that called `setItem`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a7e66481-d87f-431c-822a-3e0bc646facf', 'ca15dc81-fe48-4217-976c-ef00eba508f1', 'Only Tab A receives the event because it created the change.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('06f4b41e-f2d8-49e6-98fd-6eb4b2c0e22f', 'ca15dc81-fe48-4217-976c-ef00eba508f1', 'Tab B receives the event, but Tab A does not receive its own update through `storage`.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c52d3a8a-dbde-4225-8c2c-716bb3f841ba', 'ca15dc81-fe48-4217-976c-ef00eba508f1', 'Neither tab receives the event unless object-like access is used.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f8f6e1ba-66b9-4dda-aa19-7ae357066df8', '31189ef2-d777-4b26-9757-ee9fd1a473ef', 'Use `for...in` directly; storage objects never expose prototype members.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('66b92a22-7e21-4a63-ba00-a11db11a9e06', '31189ef2-d777-4b26-9757-ee9fd1a473ef', 'Use `Object.keys(localStorage)` or guard `for...in` with `hasOwnProperty`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5c6f2f00-bafa-43a3-9651-da326d511dc2', '31189ef2-d777-4b26-9757-ee9fd1a473ef', 'Use `localStorage.values()` because Web Storage implements the iterable protocol.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('fd82a82c-a39b-417b-8dbc-d4ce93faa29b', '31189ef2-d777-4b26-9757-ee9fd1a473ef', 'Use `Array.from(localStorage)` because storage objects are arrays.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4a9cab8d-6739-42ea-9bdd-8c858f1aef02', 'ea0a2973-20f1-4516-9353-3f5ab3f304d1', 'The same `localStorage` object is reused because the host is the same.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1dcf2860-4365-4fa1-bfa0-a824902d54a4', 'ea0a2973-20f1-4516-9353-3f5ab3f304d1', 'The storage areas are different because protocol is part of the origin.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b729298b-01c7-4e74-ac6d-cdd98d3b59c1', 'ea0a2973-20f1-4516-9353-3f5ab3f304d1', 'The data is copied automatically on first secure visit.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8dd5e428-379e-499b-8f92-15162968087d', 'ea0a2973-20f1-4516-9353-3f5ab3f304d1', 'Both pages share storage only if the keys are UTF-16 strings.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6f9742b4-963f-46c5-9c8d-1354f56eb57e', '99de661a-a57e-4af0-ab5e-8c9348ed2877', 'Values keep their original JavaScript types, but keys are converted to UTF-8.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f72c58eb-fbe5-4cf3-a253-c6ef0f749c7b', '99de661a-a57e-4af0-ab5e-8c9348ed2877', 'Keys and values are UTF-16 strings, and integer keys are converted to strings automatically.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d0392e97-cbd8-4f7d-89e6-b30e96a595cd', '99de661a-a57e-4af0-ab5e-8c9348ed2877', 'Only values are strings; keys stay numeric when inserted as integers.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d6dfd4fb-082e-401c-a922-ff4226a6ec68', '99de661a-a57e-4af0-ab5e-8c9348ed2877', 'Strings are stored as UTF-32 code points so emojis never use surrogate pairs.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('762a66a5-0a98-4f0e-bb83-1319e8ea6194', 'cfd16e2e-38d9-4fcd-9d34-302977d4e336', 'Calling `setItem` with a string longer than 255 characters.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('76a4daea-a890-4e53-aa8a-9881d3457993', 'cfd16e2e-38d9-4fcd-9d34-302977d4e336', 'Using an invalid origin like `file:` or having the browser block persistent storage.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ed862ef6-4b55-4bbe-9889-9ac44b652347', 'cfd16e2e-38d9-4fcd-9d34-302977d4e336', 'Reading from `localStorage` before `DOMContentLoaded` fires.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('515c3b5e-1f5f-4f52-8fc3-81041df7dc60', 'cfd16e2e-38d9-4fcd-9d34-302977d4e336', 'Storing a value that contains HTML markup.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2e07845a-b045-46b9-ba1a-da162f679a7c', '9edcf45a-a4f5-45d8-93b0-b0b85fe63b8d', 'It behaves exactly like normal browsing storage and remains after all private tabs are closed.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2be1129a-8727-44ca-bab2-b78ad4c2d0c0', '9edcf45a-a4f5-45d8-93b0-b0b85fe63b8d', 'It is unavailable in private browsing and always throws immediately.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e5034daa-7b81-4089-b589-9eef8e7a94f8', '9edcf45a-a4f5-45d8-93b0-b0b85fe63b8d', 'It is cleared when the last private tab is closed.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0b1c8feb-5d14-49a9-976a-7813a29d46ef', '9edcf45a-a4f5-45d8-93b0-b0b85fe63b8d', 'It is converted automatically into `sessionStorage` for the active tab only.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5f6c2be4-6bdc-4cd6-b8f9-891d3bdf4ed6', '21b6eaf0-3bae-42d3-963d-3d1d9b159c9a', 'It is fully standardized, and all `file:` URLs share one global storage area.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('842af6bb-34dd-4340-8fd3-f88d0adc5744', '21b6eaf0-3bae-42d3-963d-3d1d9b159c9a', 'It is undefined and browser-dependent, so code should not rely on a stable `file:`-URL storage model.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a5bd2c43-7b1c-418c-82e1-24565f4cfb65', '21b6eaf0-3bae-42d3-963d-3d1d9b159c9a', 'It is guaranteed that each `file:` URL uses the same storage as its nearest HTTP origin.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a4e31e6e-cead-4bc6-a445-4e679e45bf94', '21b6eaf0-3bae-42d3-963d-3d1d9b159c9a', 'It works only in Chromium-based browsers and is disabled elsewhere by spec.', FALSE, 3);
